      if (i >= values.length) return cb(true);
      cb(null, values[i++]);
    };

    const addOne = (read: Function) => (end: any, cb: Function) => {
      read(end, (end: any, data: number) => {
        if (end) return cb(end);
        cb(null, data + 1);
      });
    };

    // Create a partial sink with 5 args (length=5, so default case is needed)
    const partialSink = pull(addOne, addOne, addOne, addOne);

    // Now call it with a read function - this triggers the default case
    const piped = partialSink(simpleSource);

    // Drain the stream
    const drain = (read: Function) => {
      read(null, function next(end: any, data: number) {
        if (end === true) return;
        if (end) throw end;
        results.push(data);
        read(null, next);
      });
    };

    drain(piped);
    expect(results).toEqual([5, 6, 7]);
  });
